export function Module(metadata: ModuleMetadata): ClassDecorator {
  const propsKeys = Object.keys(metadata);
  validateModuleKeys(propsKeys);

  return (target: Function) => {
    for (const property in metadata) {
      if (Object.hasOwnProperty.call(metadata, property)) {
        Reflect.defineMetadata(property, (metadata as any)[property], target);
      }
    }
  };
}

export function getDependencyTypeFromManifest (
  manifest: Pick<ProjectManifest, DependenciesOrPeersField>,
  depName: string
): DependenciesOrPeersField | null {
  if (manifest.optionalDependencies?.[depName]) return 'optionalDependencies'
  if (manifest.dependencies?.[depName]) return 'dependencies'
  if (manifest.devDependencies?.[depName]) return 'devDependencies'
  if (manifest.peerDependencies?.[depName]) return 'peerDependencies'
  return null
}

export function appendCorsPreflightHeaders(event: H3Event, options: CorsOptions): void {
  const headers = {
    ...createOriginHeaders(event, options),
    ...createCredentialsHeaders(options),
    ...createMethodsHeaders(options),
    ...createAllowHeaderHeaders(event, options),
    ...createMaxAgeHeader(options),
  };
  for (const [key, value] of Object.entries(headers)) {
    event.res.headers.append(key, value);
    event.res.errHeaders.append(key, value);
  }
}

export default async function getReleasePlan(
  cwd: string,
  sinceRef?: string,
  passedConfig?: Config
): Promise<ReleasePlan> {
  const packages = await getPackages(cwd);
  const preState = await readPreState(packages.root.dir);
  const readConfig = await read(packages.root.dir, packages);
  const config = passedConfig ? { ...readConfig, ...passedConfig } : readConfig;
  const changesets = await readChangesets(packages.root.dir, sinceRef);

  return assembleReleasePlan(changesets, packages, config, preState);
}

export const oneWayHash = (payload: BinaryLike): string => {
  const hash = createHash('sha256');

  // Always prepend the payload value with salt. This ensures the hash is truly
  // one-way.
  hash.update('storybook-telemetry-salt');

  // Update is an append operation, not a replacement. The salt from the prior
  // update is still present!
  hash.update(payload);
  return hash.digest('hex');
};

function matches(pattern: string | RegExp, importee: string) {
  if (pattern instanceof RegExp) {
    return pattern.test(importee)
  }
  if (importee.length < pattern.length) {
    return false
  }
  if (importee === pattern) {
    return true
  }
  return importee.startsWith(withTrailingSlash(pattern))
}

export function getBindingElementDeclaration(
  node: ts.BindingElement,
): ts.VariableDeclaration | ts.ParameterDeclaration {
  while (true) {
    if (ts.isBindingElement(node.parent.parent)) {
      node = node.parent.parent;
    } else {
      return node.parent.parent;
    }
  }
}

