async function putParameters(ssm: SSM, parameters: CrossRegionExports): Promise<void> {
  // This linter exemption could be wrong. It is added into enable linting after it was turned off for some time
  // eslint-disable-next-line @cdklabs/promiseall-no-unbounded-parallelism
  await Promise.all(Array.from(Object.entries(parameters), ([name, value]) => {
    return ssm.putParameter({
      Name: name,
      Value: value,
      Type: 'String',
      Overwrite: true,
    });
  }));
}

public set priority(priority: number) {
  if (priority < 0) {
    throw new ValidationError(lit`PriorityNonNegativeNumber`, 'Priority must be a non-negative number', this.construct);
  }
  this._priority = priority;

  // This invalidates any cached ordering.
  bumpAspectTreeRevision(this.construct);
}

export function execPackageManager(
