public registerActiveGesture(element: TargetElement, gesture: Gesture<GestureName>): void {
  if (!this.activeGestures.has(element)) {
    this.activeGestures.set(element, new Set());
  }

  const elementGestures = this.activeGestures.get(element)!;
  const entry: ActiveGestureEntry<GestureName> = {
    gesture,
    element,
  };

  elementGestures.add(entry);
}

function createProjectRootMappings(
  nodes: Record<string, ProjectGraphProjectNode>
): Map<string, string> {
  const projectRootMappings = new Map<string, string>();
  for (const projectName of Object.keys(nodes)) {
    const root = nodes[projectName].data.root;

    projectRootMappings.set(normalizeProjectRoot(root), projectName);
  }
  return projectRootMappings;
}

export function updatePackageJson(filePath: string, options: PackageJsonTransformOptions): void {
  debug(`[AST] Updating package.json: ${filePath}`)

  // Phase 1: Detection
  const pkg = parsePackageJson(filePath)

  // Phase 2: Transformation
  const transformed = transformPackageJson(pkg, options)

  // Phase 3: Modification
  writePackageJson(filePath, transformed)

  debug('[AST] ✓ package.json updated successfully')
}

export function getNextPageParam(
  options: InfiniteQueryConfigOptions<unknown, unknown, unknown>,
  { pages, pageParams }: InfiniteData<unknown, unknown>,
  queryArg: unknown,
): unknown | undefined {
  const lastIndex = pages.length - 1
  return options.getNextPageParam(
    pages[lastIndex],
    pages,
    pageParams[lastIndex],
    pageParams,
    queryArg,
  )
}

function getHistoryState(location: Location, index: number): HistoryState {
  return {
    usr: location.state,
    key: location.key,
    idx: index,
    masked: location.mask
      ? {
          pathname: location.pathname,
          search: location.search,
          hash: location.hash,
        }
      : undefined,
  };
}

export function replaceMemberExpressionRootIndentifier(
  j: JSCodeshift,
  expr: MemberExpression,
  id: Identifier,
): boolean {
  if (j.Identifier.check(expr.object)) {
    expr.object = id;
    return true;
  }

  return !j.MemberExpression.check(expr.object)
    ? false
    : replaceMemberExpressionRootIndentifier(j, expr.object, id);
}

