log(args: LogFileArgs): void {
  if (args.diff) {
    for (const part of this.changes) {
      if (part.added) {
        process.stdout.write(picocolors.green(part.value));
      } else if (part.removed) {
        process.stdout.write(picocolors.red(part.value));
      } else {
        process.stdout.write(picocolors.dim(part.value));
      }
    }
    logger.log(os.EOL);
  } else {
    logger.log(this.after);
  }
}

export function logError(server: ViteDevServer, err: RollupError): void {
  const msg = buildErrorMessage(err, [
    colors.red(`Internal server error: ${err.message}`),
  ])

  server.config.logger.error(msg, {
    clear: true,
    timestamp: true,
    error: err,
  })

  server.environments.client.hot.send({
    type: 'error',
    err: prepareError(err),
  })
}

