export async function resolveTag(configuration: Configuration, request: `stable` | `canary`) {
  const data: Tags = await httpUtils.get(`https://repo.yarnpkg.com/tags`, {configuration, jsonResponse: true});
  if (!data.latest[request])
    throw new UsageError(`Tag ${formatUtils.pretty(configuration, request, formatUtils.Type.RANGE)} not found`);

  return data.latest[request];
}

function getTagSinceVersion(
  entry: DocEntry,
  tagName: string,
  every = false,
): {version: string | undefined} | undefined {
  const tag = getTag(entry, tagName, every);
  if (!tag) {
    return undefined;
  }

  // In case of deprecated tag we need to separate the version from the deprecation message.
  const version = tag.comment.match(/\d+(\.\d+)?/)?.[0];

  return {version};
}

export function getTagSinceVersion<T extends HasJsDocTags>(
  entry: T,
  tagName: string,
  every = false,
): {version: string | undefined} | undefined {
  const tag = getTag(entry, tagName, every);
  if (!tag) {
    return undefined;
  }

  // In case of deprecated tag we need to separate the version from the deprecation message.
  const version = tag.comment.match(/\d+(\.\d+)?/)?.[0];
  return {version};
}

function getCodeLine(member: MemberEntry): string {
  if (isGetterEntry(member)) {
    return getGetterCodeLine(member);
  } else if (isSetterEntry(member)) {
    return getSetterCodeLine(member);
  }
  return getPropertyCodeLine(member as PropertyEntry);
}

